import scala.util.Random
import java.time.{Instant, Duration}
import java.util.concurrent.ConcurrentHashMap
import scala.collection.concurrent
import scala.jdk.CollectionConverters._

case class SessionToken(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant,
  isActive: Boolean = true
)

case class ApiKey(
  key: String,
  secret: String,
  owner: String,
  createdAt: Instant,
  expiresAt: Option[Instant] = None,
  isActive: Boolean = true,
  scopes: Set[String] = Set.empty
)

sealed trait TokenValidationResult
case object Valid extends TokenValidationResult
case object Expired extends TokenValidationResult
case object NotFound extends TokenValidationResult
case object Revoked extends TokenValidationResult

trait TokenGenerator {
  def generateToken(length: Int = 32): String
  def generateHexToken(length: Int = 32): String
}

class DefaultTokenGenerator extends TokenGenerator {
  override def generateToken(length: Int = 32): String = {
    Random.alphanumeric.take(length).mkString
  }

  override def generateHexToken(length: Int = 32): String = {
    val bytes = new Array[Byte](length / 2)
    Random.nextBytes(bytes)
    bytes.map("%02x".format(_)).mkString
  }
}

trait SessionStore {
  def store(session: SessionToken): Unit
  def retrieve(token: String): Option[SessionToken]
  def remove(token: String): Boolean
  def findByUserId(userId: String): List[SessionToken]
  def removeAll(userId: String): Int
  def cleanup(): Int
}

class InMemorySessionStore extends SessionStore {
  private val sessions: concurrent.Map[String, SessionToken] =
    new ConcurrentHashMap[String, SessionToken]().asScala

  override def store(session: SessionToken): Unit = {
    sessions.put(session.token, session)
  }

  override def retrieve(token: String): Option[SessionToken] = {
    sessions.get(token)
  }

  override def remove(token: String): Boolean = {
    sessions.remove(token).isDefined
  }

  override def findByUserId(userId: String): List[SessionToken] = {
    sessions.values.filter(_.userId == userId).toList
  }

  override def removeAll(userId: String): Int = {
    val userSessions = findByUserId(userId)
    userSessions.foreach(s => sessions.remove(s.token))
    userSessions.size
  }

  override def cleanup(): Int = {
    val now = Instant.now()
    val expired = sessions.values.filter(s => s.expiresAt.isBefore(now) || !s.isActive).toList
    expired.foreach(s => sessions.remove(s.token))
    expired.size
  }
}

trait ApiKeyStore {
  def store(apiKey: ApiKey): Unit
  def retrieve(key: String): Option[ApiKey]
  def revoke(key: String): Boolean
  def findByOwner(owner: String): List[ApiKey]
}

class InMemoryApiKeyStore extends ApiKeyStore {
  private val apiKeys: concurrent.Map[String, ApiKey] =
    new ConcurrentHashMap[String, ApiKey]().asScala

  override def store(apiKey: ApiKey): Unit = {
    apiKeys.put(apiKey.key, apiKey)
  }

  override def retrieve(key: String): Option[ApiKey] = {
    apiKeys.get(key)
  }

  override def revoke(key: String): Boolean = {
    apiKeys.get(key) match {
      case Some(ak) =>
        apiKeys.put(key, ak.copy(isActive = false))
        true
      case None => false
    }
  }

  override def findByOwner(owner: String): List[ApiKey] = {
    apiKeys.values.filter(_.owner == owner).toList
  }
}

class TokenGenerationService(
  tokenGenerator: TokenGenerator = new DefaultTokenGenerator(),
  sessionStore: SessionStore = new InMemorySessionStore(),
  apiKeyStore: ApiKeyStore = new InMemoryApiKeyStore(),
  defaultSessionDuration: Duration = Duration.ofHours(24),
  maxSessionsPerUser: Int = 5
) {

  def createSession(userId: String, durationOverride: Option[Duration] = None): SessionToken = {
    val existingSessions = sessionStore.findByUserId(userId).filter(_.isActive)
    if (existingSessions.size >= maxSessionsPerUser) {
      val oldest = existingSessions.sortBy(_.createdAt).head
      sessionStore.remove(oldest.token)
    }

    val now = Instant.now()
    val duration = durationOverride.getOrElse(defaultSessionDuration)
    val token = Random.alphanumeric.take(32).mkString

    val session = SessionToken(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(duration)
    )

    sessionStore.store(session)
    session
  }

  def validateSession(token: String): TokenValidationResult = {
    sessionStore.retrieve(token) match {
      case None => NotFound
      case Some(session) if !session.isActive => Revoked
      case Some(session) if session.expiresAt.isBefore(Instant.now()) =>
        invalidateSession(token)
        Expired
      case Some(_) => Valid
    }
  }

  def refreshSession(token: String, durationOverride: Option[Duration] = None): Option[SessionToken] = {
    sessionStore.retrieve(token) match {
      case Some(session) if session.isActive && session.expiresAt.isAfter(Instant.now()) =>
        val duration = durationOverride.getOrElse(defaultSessionDuration)
        val refreshedSession = session.copy(expiresAt = Instant.now().plus(duration))
        sessionStore.store(refreshedSession)
        Some(refreshedSession)
      case _ => None
    }
  }

  def invalidateSession(token: String): Boolean = {
    sessionStore.retrieve(token) match {
      case Some(session) =>
        sessionStore.store(session.copy(isActive = false))
        sessionStore.remove(token)
      case None => false
    }
  }

  def invalidateAllSessions(userId: String): Int = {
    sessionStore.removeAll(userId)
  }

  def getSession(token: String): Option[SessionToken] = {
    sessionStore.retrieve(token).filter(s => s.isActive && s.expiresAt.isAfter(Instant.now()))
  }

  def createApiKey(owner: String, scopes: Set[String] = Set.empty, expiration: Option[Duration] = None): ApiKey = {
    val key = Random.alphanumeric.take(32).mkString
    val secret = tokenGenerator.generateHexToken(64)
    val now = Instant.now()

    val apiKey = ApiKey(
      key = key,
      secret = secret,
      owner = owner,
      createdAt = now,
      expiresAt = expiration.map(now.plus),
      scopes = scopes
    )

    apiKeyStore.store(apiKey)
    apiKey
  }

  def validateApiKey(key: String): TokenValidationResult = {
    apiKeyStore.retrieve(key) match {
      case None => NotFound
      case Some(ak) if !ak.isActive => Revoked
      case Some(ak) if ak.expiresAt.exists(_.isBefore(Instant.now())) => Expired
      case Some(_) => Valid
    }
  }

  def validateApiKeyWithScopes(key: String, requiredScopes: Set[String]): Either[TokenValidationResult, ApiKey] = {
    apiKeyStore.retrieve(key) match {
      case None => Left(NotFound)
      case Some(ak) if !ak.isActive => Left(Revoked)
      case Some(ak) if ak.expiresAt.exists(_.isBefore(Instant.now())) => Left(Expired)
      case Some(ak) if !requiredScopes.subsetOf(ak.scopes) => Left(Revoked)
      case Some(ak) => Right(ak)
    }
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeyStore.revoke(key)
  }

  def getApiKeysByOwner(owner: String): List[ApiKey] = {
    apiKeyStore.findByOwner(owner).filter(_.isActive)
  }

  def cleanupExpiredSessions(): Int = {
    sessionStore.cleanup()
  }

  def generateCsrfToken(): String = {
    Random.alphanumeric.take(32).mkString
  }

  def generatePasswordResetToken(): String = {
    tokenGenerator.generateHexToken(48)
  }

  def generateEmailVerificationToken(): String = {
    tokenGenerator.generateHexToken(32)
  }
}

object TokenGenerationService {
  def apply(): TokenGenerationService = new TokenGenerationService()

  def apply(sessionDuration: Duration, maxSessions: Int): TokenGenerationService = {
    new TokenGenerationService(
